You would want to modularize the response handling so that it can be used from any function.

`job_utils.py`
```
@respond_to("^SERIOUSLY clear all waiting jobs$")
def clear_waiting_jobs(self, message):
    jobs = self.load("awaiting_confirmation", [])
    self.save("awaiting_confirmation", [])

    self.reply("Cleared {} job(s)!".format(len(jobs)))

def save_command(job_type, callback, message):
    job = { "job_type": job_type, "caller": message.sender["hipchat_id"], "callback": callback }
    
    jobs = self.load("awaiting_confirmation", [])
    jobs.append(job )

    self.save("awaiting_confirmation", job )

    self.ask_for_confirmation(message)

def ask_for_confirmation(self, message)
    self.reply(message, "Are you sure? (reply yes or no)")

@respond_to("^yes$")
def yes(self, message):
    # check redis store for commands which needs confirmation
    # if there is a pending command which needs confirmation, make sure that the person confirming is also the person who issued the command. Then run the callback and remove command from redis store
    # otherwise; either ignore the message or reply with "no jobs need confirmation!"

@respond_to("^no$")
def no(self, message):
    # check for commands
    # remove command without running callback
```

