I will leave it to you then. But can give you my implementation which I have not pushed yet:

```python
class RefLabelMixin(CommandBase):
    @classmethod
    def sec(cls, name):
        return cls(name, prefix='sec')

    @classmethod
    def sub(cls, name):
        return cls(name, prefix='sub')

    @classmethod
    def ssub(cls, name):
        return cls(name, prefix='ssub')

    @classmethod
    def fig(cls, name):
        return cls(name, prefix='fig')

    @classmethod
    def tab(cls, name):
        return cls(name, prefix='tab')

    @classmethod
    def theo(cls, name):
        return cls(name, prefix='theo')


class Label(RefLabelMixin):
    def __init__(self, name, prefix=''):
        name = '{}:{}'.format(prefix, name)
        super(Label, self).__init__(arguments=NoEscape(name))


class Ref(RefLabelMixin):
    def __init__(self, name, prefix=''):
        name = '{}:{}'.format(prefix, name)
        super(Ref, self).__init__(arguments=NoEscape(name))
```

