Here's some (uncommitted) code I used to test unchecked performance when implementing unchecked references.  I think you could easily add an iteration version (for comparison of the iterator approach performance vs loops):

### unsafe.cpp:
```C++
#include <pybind11/pybind11.h>
#include <pybind11/numpy.h>

namespace py = pybind11;

double squared(double x) {
    return x*x;
}

PYBIND11_PLUGIN(unsafe) {
    py::module m("unsafe");

    m.def("incr_dbl_1D", [](py::array a) {
        auto r = a.mutable_unchecked<double, 1>();
        for (size_t i = 0; i < r.shape(0); i++)
            r[i]++;
    });
